function solve(n, edges) {
    class PriorityQueue {
        constructor() {
            this.heap = [];
            this.size = 0;
        }
        push(value) {
            this.heap.push(value);
            this.size++;
            this.heapifyUp(this.size - 1);
        }
        pop() {
            if (this.size === 0) return null;
            const val = this.heap[0];
            this.heap[0] = this.heap[this.size - 1];
            this.size--;
            this.heapifyDown(0);
            return val;
        }
        heapifyUp(index) {
            while (index > 0) {
                const parent = Math.floor((index - 1) / 2);
                if (this.heap[index][0] < this.heap[parent][0]) {
                    [this.heap[index], this.heap[parent]] = [this.heap[parent], this.heap[index]];
                    index = parent;
                } else {
                    break;
                }
            }
        }
        heapifyDown(index) {
            while (index < this.size) {
                const left = 2 * index + 1;
                const right = 2 * index + 2;
                let smallest = index;
                if (left < this.size && this.heap[left][0] < this.heap[smallest][0]) {
                    smallest = left;
                }
                if (right < this.size && this.heap[right][0] < this.heap[smallest][0]) {
                    smallest = right;
                }
                if (smallest !== index) {
                    [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
                    index = smallest;
                } else {
                    break;
                }
            }
        }
    }

    const outgoing = new Array(n).fill().map(() => []);
    const incoming = new Array(n).fill().map(() => []);
    for (const [u, v, w] of edges) {
        outgoing[u].push([v, w]);
        incoming[v].push([u, w]);
    }

    const dist = new Array(n).fill(0).map(() => new Array(2).fill(Infinity));
    dist[0][0] = 0;

    const pq = new PriorityQueue();
    pq.push([0, 0, 0]);

    while (pq.size > 0) {
        const [cost, u, s] = pq.pop();
        if (dist[u][s] < cost) continue;
        if (u === n - 1) return cost;

        if (s === 0) {
            for (const [v, w] of outgoing[u]) {
                const newCost = cost + w;
                if (newCost < dist[v][0]) {
                    dist[v][0] = newCost;
                    pq.push([newCost, v, 0]);
                }
            }
            for (const [v, w] of incoming[u]) {
                const newCost = cost + 2 * w;
                if (newCost < dist[v][1]) {
                    dist[v][1] = newCost;
                    pq.push([newCost, v, 1]);
                }
            }
        } else {
            for (const [v, w] of outgoing[u]) {
                const newCost = cost + w;
                if (newCost < dist[v][1]) {
                    dist[v][1] = newCost;
                    pq.push([newCost, v, 1]);
                }
            }
        }
    }

    const min = Math.min(dist[n - 1][0], dist[n - 1][1]);
    return min === Infinity ? -1 : min;
}

