import heapq

def solve(n: int, edges: list[list[int]]) -> int:
    outgoing = [[] for _ in range(n)]
    incoming = [[] for _ in range(n)]
    for u, v, w in edges:
        outgoing[u].append((v, w))
        incoming[v].append((u, w))

    dist = [[float('inf')] * 2 for _ in range(n)]
    dist[0][0] = 0
    heap = []
    heapq.heappush(heap, (0, 0, 0))

    while heap:
        cost, u, s = heapq.heappop(heap)
        if u == n - 1:
            return cost
        if cost > dist[u][s]:
            continue
        if s == 0:
            for v, w in outgoing[u]:
                new_cost = cost + w
                if new_cost < dist[v][0]:
                    dist[v][0] = new_cost
                    heapq.heappush(heap, (new_cost, v, 0))
            for v, w in incoming[u]:
                new_cost = cost + 2 * w
                if new_cost < dist[v][1]:
                    dist[v][1] = new_cost
                    heapq.heappush(heap, (new_cost, v, 1))
